"categories": {
  "kitchen_scene": {
    "desc": "厨房场景背景与操作台，用于游戏主场景布局",
    "assets": ["kitchenfloorbackground", "kitchen", "cooking-table", "manager-desk"]
  },
  "chef_animation": {
    "desc": "厨师角色动画帧序列，用于烹饪/行走/端菜动画",
    "assets": {
      "cooking": { "ids": "chef_cooking_00 ~ chef_cooking_29", "frame_count": 30, "usage": "烹饪进度条播放期间循环播放" },
      "walk": { "ids": "chef_walk_00 ~ chef_walk_19", "frame_count": 20, "usage": "厨师在场景中移动时播放" },
      "walk_with_pizza": { "ids": "chef_walk_with_pizza_00 ~ chef_walk_with_pizza_19", "frame_count": 20, "usage": "持菜品走向顾客时播放" }
    }
  },
  "customer": {
    "desc": "顾客角色动画帧，用于顾客区域展示等待中的顾客",
    "assets": {
      "floor_manager_idle": { "ids": "floor_manager_00 ~ floor_manager_09", "frame_count": 10, "usage": "顾客等待待机动画" },
      "floor_manager_icon": "floormanagericon"
    }
  },
  "hud_ui": {
    "desc": "游戏HUD界面元素：订单列表、分数、倒计时",
    "assets": ["coinicon", "clockicon", "orangebox1", "orangebox2", "yellowbar", "greenbar", "moneybar1", "moneybar2", "cheficon"]
  },
  "progress_bar": {
    "desc": "进度条素材，用于烹饪4秒进度条和顾客patience条",
    "assets": {
      "patience_bar_bg": "moneybar1",
      "patience_bar_fill": "moneybar2",
      "cook_bar_bg": "orangebox3",
      "cook_bar_fill": "greenbar"
    }
  },
  "buttons": {
    "desc": "可点击按钮，用于开始游戏/重新开始等交互",
    "assets": {
      "start_btn": "greenbtn1",
      "restart_btn": "greenbtn1",
      "small_btn": "greenbtn2",
      "close_btn": "closebtn"
    }
  },
  "popup": {
    "desc": "弹窗背景，用于结算页面（胜利/失败提示）",
    "assets": ["popupbox1", "popupbox2"]
  },
  "food_item": {
    "desc": "食材与菜品图标，用于订单展示和持有状态",
    "assets": ["pizza"]
  }
},
"phaser_config": {
  "load_method": "image",
  "load_code_template": "this.load.image(KEY, 'assets/cooking-pizza/' + FILE);",
  "usage_template": "this.add.image(x, y, KEY);",
  "prd_load_code": {
    "comment": "在 Phaser Scene preload() 中加载 K12小厨房模拟 所需资产",
    "scene_background": [
      "this.load.image('kitchenfloorbackground', 'assets/cooking-pizza/Png/User_Interfaces/KitchenFloorBackground.png');",
      "this.load.image('kitchen', 'assets/cooking-pizza/Png/Others/Kitchen.png');",
      "this.load.image('cooking-table', 'assets/cooking-pizza/Png/Others/cooking-table.png');",
      "this.load.image('manager-desk', 'assets/cooking-pizza/Png/Others/Manager-Desk.png');"
    ],
    "chef_animation_frames": [
      "// 厨师烹饪动画 30帧 (chef_cooking_00 ~ chef_cooking_29)",
      "for (let i = 0; i <= 29; i++) { const pad = String(i).padStart(2,'0'); this.load.image(`chef_cooking_${pad}`, `assets/cooking-pizza/Png/Sprite_Set/Chef_Cooking/Chef_Cooking_${pad}.png`); }",
      "// 厨师行走动画 20帧 (chef_walk_00 ~ chef_walk_19)",
      "for (let i = 0; i <= 19; i++) { const pad = String(i).padStart(2,'0'); this.load.image(`chef_walk_${pad}`, `assets/cooking-pizza/Png/Sprite_Set/Chef_Walk/Chef_Walk_${pad}.png`); }",
      "// 厨师端披萨行走动画 20帧 (chef_walk_with_pizza_00 ~ chef_walk_with_pizza_19)",
      "for (let i = 0; i <= 19; i++) { const pad = String(i).padStart(2,'0'); this.load.image(`chef_walk_with_pizza_${pad}`, `assets/cooking-pizza/Png/Sprite_Set/Chef_Walk_With_Pizza/Chef_Walk_With_Pizza_${pad}.png`); }"
    ],
    "customer_frames": [
      "// 顾客待机动画 10帧 (floor_manager_00 ~ floor_manager_09)",
      "for (let i = 0; i <= 9; i++) { const pad = String(i).padStart(2,'0'); this.load.image(`floor_manager_${pad}`, `assets/cooking-pizza/Png/Sprite_Set/Floor_Manager/Floor_Manager_${pad}.png`); }",
      "this.load.image('floormanagericon', 'assets/cooking-pizza/Png/User_Interfaces/FloorManagerIcon.png');"
    ],
    "hud_ui": [
      "this.load.image('coinicon', 'assets/cooking-pizza/Png/User_Interfaces/CoinIcon.png');",
      "this.load.image('clockicon', 'assets/cooking-pizza/Png/User_Interfaces/ClockIcon.png');",
      "this.load.image('orangebox1', 'assets/cooking-pizza/Png/User_Interfaces/OrangeBox1.png');",
      "this.load.image('orangebox2', 'assets/cooking-pizza/Png/User_Interfaces/OrangeBox2.png');",
      "this.load.image('orangebox3', 'assets/cooking-pizza/Png/User_Interfaces/OrangeBox3.png');",
      "this.load.image('yellowbar', 'assets/cooking-pizza/Png/User_Interfaces/YellowBar.png');",
      "this.load.image('greenbar', 'assets/cooking-pizza/Png/User_Interfaces/GreenBar.png');",
      "this.load.image('moneybar1', 'assets/cooking-pizza/Png/User_Interfaces/MoneyBar1.png');",
      "this.load.image('moneybar2', 'assets/cooking-pizza/Png/User_Interfaces/MoneyBar2.png');",
      "this.load.image('cheficon', 'assets/cooking-pizza/Png/User_Interfaces/ChefIcon.png');"
    ],
    "buttons": [
      "this.load.image('greenbtn1', 'assets/cooking-pizza/Png/User_Interfaces/GreenBtn1.png');",
      "this.load.image('greenbtn2', 'assets/cooking-pizza/Png/User_Interfaces/GreenBtn2.png');",
      "this.load.image('closebtn', 'assets/cooking-pizza/Png/User_Interfaces/CloseBtn.png');"
    ],
    "popup": [
      "this.load.image('popupbox1', 'assets/cooking-pizza/Png/User_Interfaces/PopupBox1.png');",
      "this.load.image('popupbox2', 'assets/cooking-pizza/Png/User_Interfaces/PopupBox2.png');"
    ],
    "food": [
      "this.load.image('pizza', 'assets/cooking-pizza/Png/Others/Pizza.png');"
    ]
  },
  "prd_usage": {
    "comment": "K12小厨房模拟 各场景用法示例",
    "start_scene": {
      "comment": "开始游戏页面",
      "background": "const bg = this.add.image(400, 300, 'kitchenfloorbackground').setDisplaySize(800, 600);",
      "start_button": "const startBtn = this.add.image(400, 400, 'greenbtn1').setInteractive(); startBtn.on('pointerdown', () => this.scene.start('GameScene'));"
    },
    "game_scene": {
      "comment": "游戏主场景",
      "background": "const bg = this.add.image(400, 300, 'kitchenfloorbackground').setDisplaySize(800, 600);",
      "kitchen_bg": "const kitchen = this.add.image(400, 300, 'kitchen');",
      "cooking_table": "const stove = this.add.image(400, 420, 'cooking-table').setInteractive(); // 炉灶热区",
      "fridge_zone": "const fridge = this.add.image(150, 350, 'kitchen').setInteractive(); // 冰箱热区（用厨房背景区域划定）",
      "chef_idle": "const chef = this.add.image(300, 350, 'chef_cooking_00'); // 厨师初始帧",
      "chef_cook_anim": "// 烹饪动画：用 Phaser.Time.addEvent 每帧切换\nlet cookFrame = 0;\nconst cookTimer = this.time.addEvent({ delay: 133, loop: true, callback: () => { cookFrame = (cookFrame + 1) % 30; const pad = String(cookFrame).padStart(2,'0'); chef.setTexture(`chef_cooking_${pad}`); } });",
      "chef_walk_anim": "// 行走动画\nlet walkFrame = 0;\nconst walkTimer = this.time.addEvent({ delay: 100, loop: true, callback: () => { walkFrame = (walkFrame + 1) % 20; const pad = String(walkFrame).padStart(2,'0'); chef.setTexture(`chef_walk_${pad}`); } });",
      "chef_deliver_anim": "// 端菜行走动画（上菜阶段）\nlet deliverFrame = 0;\nconst deliverTimer = this.time.addEvent({ delay: 100, loop: true, callback: () => { deliverFrame = (deliverFrame + 1) % 20; const pad = String(deliverFrame).padStart(2,'0'); chef.setTexture(`chef_walk_with_pizza_${pad}`); } });",
      "customer": "const customer = this.add.image(650, 350, 'floor_manager_00').setInteractive(); // 顾客区域",
      "customer_anim": "// 顾客待机动画\nlet custFrame = 0;\nthis.time.addEvent({ delay: 150, loop: true, callback: () => { custFrame = (custFrame + 1) % 10; const pad = String(custFrame).padStart(2,'0'); customer.setTexture(`floor_manager_${pad}`); } });",
      "food_item": "const foodItem = this.add.image(300, 300, 'pizza').setVisible(false); // 食材/菜品图标，取料后显示",
      "cook_progress_bar": "// 烹饪4秒进度条\nconst barBg = this.add.image(400, 460, 'orangebox3');\nconst barFill = this.add.image(400, 460, 'greenbar').setOrigin(0, 0.5);\nconst cookDuration = 4000;\nthis.tweens.add({ targets: barFill, scaleX: 1, from: 0, duration: cookDuration, onComplete: () => { /* 烹饪完成 */ } });",
      "patience_bar": "// 顾客patience条\nconst patienceBg = this.add.image(650, 300, 'moneybar1');\nconst patienceFill = this.add.image(650, 300, 'moneybar2').setOrigin(0, 0.5);\nthis.tweens.add({ targets: patienceFill, scaleX: 0, duration: 30000, onComplete: () => { /* 顾客离开 */ } });",
      "score_display": "const coinIcon = this.add.image(50, 30, 'coinicon');\nconst scoreText = this.add.text(80, 20, '0', { fontSize: '24px', fill: '#fff' });",
      "timer_display": "const clockIcon = this.add.image(700, 30, 'clockicon');\nconst timerText = this.add.text(730, 20, '2:00', { fontSize: '24px', fill: '#fff' });",
      "order_hud": "// 订单列表HUD背景\nconst orderBg = this.add.image(120, 150, 'orangebox2');\nconst custIcon = this.add.image(100, 130, 'floormanagericon').setScale(0.5);"
    },
    "result_scene": {
      "comment": "结算页面",
      "popup_bg": "const popup = this.add.image(400, 300, 'popupbox1').setDisplaySize(400, 300);",
      "result_text": "const resultText = this.add.text(400, 220, '胜利！', { fontSize: '36px', fill: '#fff' }).setOrigin(0.5);",
      "score_text": "const finalScore = this.add.text(400, 280, '得分: 300', { fontSize: '24px', fill: '#fff' }).setOrigin(0.5);",
      "restart_button": "const restartBtn = this.add.image(400, 360, 'greenbtn1').setInteractive(); restartBtn.on('pointerdown', () => this.scene.start('StartScene'));"
    }
  },
  "animation_summary": {
    "chef_cooking": { "key_prefix": "chef_cooking_", "frames": 30, "frame_range": "00-29", "fps": 7, "loop": true, "use_case": "炉灶烹饪进度条播放期间" },
    "chef_walk": { "key_prefix": "chef_walk_", "frames": 20, "frame_range": "00-19", "fps": 10, "loop": true, "use_case": "厨师移动至冰箱/炉灶/顾客" },
    "chef_walk_with_pizza": { "key_prefix": "chef_walk_with_pizza_", "frames": 20, "frame_range": "00-19", "fps": 10, "loop": true, "use_case": "持菜品走向顾客上菜" },
    "customer_idle": { "key_prefix": "floor_manager_", "frames": 10, "frame_range": "00-09", "fps": 6, "loop": true, "use_case": "顾客等待区域待机" }
  }
}

