### 二、各场景 create() 用法

#### 开始游戏页面
```js
this.add.image(400, 300, 'kitchenfloorbackground').setDisplaySize(800, 600); // 背景
const startBtn = this.add.image(400, 400, 'greenbtn1').setInteractive();
startBtn.on('pointerdown', () => this.scene.start('GameScene'));
```

#### 游戏主场景
```js
// 背景
this.add.image(400, 300, 'kitchenfloorbackground').setDisplaySize(800, 600);
// 炉灶热区（可点击）
const stove = this.add.image(400, 420, 'cooking-table').setInteractive();
// 冰箱热区（用 manager-desk 或划定区域）
const fridge = this.add.image(150, 350, 'manager-desk').setInteractive();
// 厨师角色（初始帧）
const chef = this.add.image(300, 350, 'chef_cooking_00');
// 顾客（可点击）
const customer = this.add.image(650, 350, 'floor_manager_00').setInteractive();
// 食材图标（取料后显示）
const foodItem = this.add.image(300, 300, 'pizza').setVisible(false);
```

#### 动画播放（逐帧切换）
```js
// 烹饪动画（4秒内循环，约7fps）
let cookFrame = 0;
const cookTimer = this.time.addEvent({
  delay: 133, loop: true,
  callback: () => { cookFrame = (cookFrame + 1) % 30; chef.setTexture(`chef_cooking_${String(cookFrame).padStart(2,'0')}`); }
});

// 行走动画（10fps）
let walkFrame = 0;
const walkTimer = this.time.addEvent({
  delay: 100, loop: true,
  callback: () => { walkFrame = (walkFrame + 1) % 20; chef.setTexture(`chef_walk_${String(walkFrame).padStart(2,'0')}`); }
});

// 端菜行走动画（上菜阶段，10fps）
let dFrame = 0;
const dTimer = this.time.addEvent({
  delay: 100, loop: true,
  callback: () => { dFrame = (dFrame + 1) % 20; chef.setTexture(`chef_walk_with_pizza_${String(dFrame).padStart(2,'0')}`); }
});

// 顾客待机动画（6fps）
let cFrame = 0;
this.time.addEvent({
  delay: 150, loop: true,
  callback: () => { cFrame = (cFrame + 1) % 10; customer.setTexture(`floor_manager_${String(cFrame).padStart(2,'0')}`); }
});
```

#### 进度条（烹饪4秒 + 顾客patience）
```js
// 烹饪进度条（4秒）
const barBg   = this.add.image(400, 460, 'orangebox3');
const barFill = this.add.image(370, 460, 'greenbar').setOrigin(0, 0.5).setScaleX(0);
this.tweens.add({ targets: barFill, scaleX: 1, duration: 4000, onComplete: () => { /* 烹饪完成 */ } });

// 顾客patience条（随时间递减）
const pBg   = this.add.image(650, 300, 'moneybar1');
const pFill = this.add.image(620, 300, 'moneybar2').setOrigin(0, 0.5);
this.tweens.add({ targets: pFill, scaleX: 0, duration: 30000, onComplete: () => { /* 顾客离开 */ } });
```

#### HUD（分数 + 倒计时 + 订单列表）
```js
this.add.image(50, 30, 'coinicon');
const scoreText = this.add.text(80, 20, '0', { fontSize: '24px', fill: '#fff' });
this.add.image(700, 30, 'clockicon');
const timerText = this.add.text(730, 20, '2:00', { fontSize: '24px', fill: '#fff' });
// 订单列表背景
this.add.image(120, 150, 'orangebox2');
this.add.image(100, 130, 'floormanagericon').setScale(0.5);
```

#### 结算页面
```js
this.add.image(400, 300, 'popupbox1').setDisplaySize(400, 300);
this.add.text(400, 220, '胜利！', { fontSize: '36px', fill: '#fff' }).setOrigin(0.5);
this.add.text(400, 280, '得分: 300', { fontSize: '24px', fill: '#fff' }).setOrigin(0.5);
const restartBtn = this.add.image(400, 360, 'greenbtn1').setInteractive();
restartBtn.on('pointerdown', () => this.scene.start('StartScene'));
```

---

### 三、动画帧汇总

| 动画名 | key前缀 | 帧数 | 帧范围 | 推荐fps | 使用场景 |
|--------|---------|------|--------|---------|---------|
| 厨师烹饪 | `chef_cooking_` | 30 | 00-29 | 7 | 炉灶烹饪进度条期间 |
| 厨师行走 | `chef_walk_` | 20 | 00-19 | 10 | 移动至冰箱/炉灶/顾客 |
| 厨师端菜 | `chef_walk_with_pizza_` | 20 | 00-19 | 10 | 上菜阶段 |
| 顾客待机 | `floor_manager_` | 10 | 00-09 | 6 | 顾客等待区域 |

### 四、注意事项
- 所有动画均为**独立PNG帧**，需用 `this.time.addEvent` 手动切换 `setTexture()` 实现动画效果
- 进度条使用 `setScaleX()` + `this.tweens.add()` 实现填充动画
- 按钮需调用 `.setInteractive()` 后才能响应点击事件
- 文件路径区分大小写，请严格按 manifest.json 中的 `file` 字段使用

