import fs from 'fs';
import path from 'path';

const manifestPath = '/workspace/app-cikz7rz45fy9/src/assets/manifest.json';
const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));

let output = '';
let preloadCode = 'export function preloadAssets(scene: Phaser.Scene) {\n';

manifest.assets.forEach((asset: any) => {
  // Only process images (PNG) to avoid spine files if we aren't using spine
  if (!asset.file.endsWith('.png')) return;
  if (asset.file.startsWith('Spine')) return; // Ignore Spine skeletons for this simple game, we use sprite frames

  const varName = asset.id.replace(/-/g, '_').replace(/[^a-zA-Z0-9_]/g, '');
  const relativePath = `../assets/cooking-pizza/${asset.file}`;

  output += `import ${varName} from '${relativePath}';\n`;
  preloadCode += `  scene.load.image('${asset.id}', ${varName});\n`;
});

preloadCode += '}\n';

fs.writeFileSync('/workspace/app-cikz7rz45fy9/src/game/assets.ts', output + '\n' + preloadCode);
console.log('Done!');

import { Phaser } from 'phaser';
// Note: We'll define EventBus to communicate between Phaser and React
export const EventBus = new Phaser.Events.EventEmitter();

import { create } from 'zustand';

export type OrderStatus = 'pending' | 'cooking' | 'serving' | 'completed' | 'failed';

export interface Order {
  id: string;
  patience: number;
  maxPatience: number;
  status: OrderStatus;
}

interface GameState {
  score: number;
  timeRemaining: number;
  orders: Order[];
  completedOrders: number;
  gameStatus: 'idle' | 'playing' | 'won' | 'lost';

  // Actions
  addScore: (points: number) => void;
  updateTime: (time: number) => void;
  addOrder: (order: Order) => void;
  updateOrderPatience: (id: string, patience: number) => void;
  updateOrderStatus: (id: string, status: OrderStatus) => void;
  completeOrder: (id: string) => void;
  failOrder: (id: string) => void;
  setGameStatus: (status: 'idle' | 'playing' | 'won' | 'lost') => void;
  resetGame: () => void;
}

export const useGameStore = create<GameState>((set) => ({
  score: 0,
  timeRemaining: 120, // 2 minutes
  orders: [],
  completedOrders: 0,
  gameStatus: 'idle',

  addScore: (points) => set((state) => ({ score: state.score + points })),
  updateTime: (time) => set({ timeRemaining: time }),

  addOrder: (order) => set((state) => ({
    orders: state.orders.length < 3 ? [...state.orders, order] : state.orders
  })),

  updateOrderPatience: (id, patience) => set((state) => ({
    orders: state.orders.map(o => o.id === id ? { ...o, patience } : o)
  })),

  updateOrderStatus: (id, status) => set((state) => ({
    orders: state.orders.map(o => o.id === id ? { ...o, status } : o)
  })),

  completeOrder: (id) => set((state) => {
    const updatedOrders = state.orders.filter(o => o.id !== id);
    return {
      orders: updatedOrders,
      completedOrders: state.completedOrders + 1,
      score: state.score + 100 // 100 points for completion
    };
  }),

  failOrder: (id) => set((state) => {
    const updatedOrders = state.orders.filter(o => o.id !== id);
    return {
      orders: updatedOrders,
      score: Math.max(0, state.score - 50) // -50 points for failure
    };
  }),

  setGameStatus: (status) => set({ gameStatus: status }),

  resetGame: () => set({
    score: 0,
    timeRemaining: 120,
    orders: [],
    completedOrders: 0,
    gameStatus: 'idle'
  })
}));

export const GAME_DURATION = 120; // 2 minutes
export const ORDERS_TO_WIN = 3;
export const COOKING_TIME = 4000; // 4 seconds
export const PATIENCE_TIME = 30000; // 30 seconds patience per order
export const POINTS_PER_ORDER = 100;
export const PENALTY_PER_ORDER = 50;

import { Scene } from 'phaser';
import { preloadAssets } from '../assets';

export class Boot extends Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    // Generate fallback textures for missing assets
    this.load.on('loaderror', (file: any) => {
      const g = this.add.graphics();
      const w = this.game.config.width as number;
      const h = this.game.config.height as number;
      g.fillGradientStyle(0x667788, 0x334455, 0x334455, 0x667788);
      g.fillRect(0, 0, w, h);
      g.generateTexture(file.key, w, h);
      g.destroy();
    });

    preloadAssets(this);
  }

  create() {
    this.scene.start('Game');
  }
}

import { Scene, GameObjects, Time, Tweens } from 'phaser';
import { EventBus } from '../EventBus';
import { useGameStore } from '../model/store';
import { COOKING_TIME, PATIENCE_TIME, ORDERS_TO_WIN } from '../constants';

export class Game extends Scene {
  private chef!: GameObjects.Image;
  private customer!: GameObjects.Image;
  private stove!: GameObjects.Image;
  private fridge!: GameObjects.Image;
  private foodItem!: GameObjects.Image;

  // Progress bars
  private cookBarFill!: GameObjects.Image;
  private cookBarBg!: GameObjects.Image;

  // Animations
  private cookTimer?: Time.TimerEvent;
  private walkTimer?: Time.TimerEvent;
  private deliverTimer?: Time.TimerEvent;
  private customerTimer?: Time.TimerEvent;

  // Game state
  private playerState: 'idle' | 'holding_ingredient' | 'cooking' | 'holding_food' = 'idle';
  private cookTween?: Tweens.Tween;

  private lastTimeSync = 0;

  constructor() {
    super('Game');
  }

  create() {
    this.playerState = 'idle';

    // Background
    this.add.image(400, 300, 'kitchenfloorbackground').setDisplaySize(800, 600);

    // Stove area
    this.stove = this.add.image(400, 420, 'cooking-table').setInteractive();

    // Fridge area (using manager desk)
    this.fridge = this.add.image(150, 350, 'manager-desk').setInteractive();

    // Customer area
    this.customer = this.add.image(650, 350, 'floor_manager_00').setInteractive();

    // Chef
    this.chef = this.add.image(300, 350, 'chef_walk_00');

    // Food item
    this.foodItem = this.add.image(300, 300, 'pizza').setVisible(false).setScale(0.5);

    // Cook progress bar
    this.cookBarBg = this.add.image(400, 460, 'orangebox3').setVisible(false);
    this.cookBarFill = this.add.image(370, 460, 'greenbar').setOrigin(0, 0.5).setScaleX(0).setVisible(false);

    // Animations setup
    let cFrame = 0;
    this.customerTimer = this.time.addEvent({
      delay: 150, loop: true,
      callback: () => {
        cFrame = (cFrame + 1) % 10;
        this.customer.setTexture(`floor_manager_${String(cFrame).padStart(2,'0')}`);
      }
    });

    // Inputs
    this.fridge.on('pointerdown', this.handleFridgeClick, this);
    this.stove.on('pointerdown', this.handleStoveClick, this);
    this.customer.on('pointerdown', this.handleCustomerClick, this);

    // Pointer animations
    const pressTween = (target: GameObjects.Image) => {
      this.tweens.add({
        targets: target,
        y: target.y + 5,
        duration: 50,
        yoyo: true
      });
    };

    [this.fridge, this.stove, this.customer].forEach(obj => {
      obj.on('pointerdown', () => pressTween(obj));
    });

    // Event bus handlers
    EventBus.on('start-game', this.startGame, this);
    EventBus.on('restart-game', this.startGame, this);
    EventBus.on('generate-order', this.generateOrder, this);

    this.playIdleAnim();
  }

  private stopAnims() {
    if (this.cookTimer) this.cookTimer.destroy();
    if (this.walkTimer) this.walkTimer.destroy();
    if (this.deliverTimer) this.deliverTimer.destroy();
  }

  private playIdleAnim() {
    this.stopAnims();
    let walkFrame = 0;
    this.walkTimer = this.time.addEvent({
      delay: 100, loop: true,
      callback: () => {
        walkFrame = (walkFrame + 1) % 20;
        this.chef.setTexture(`chef_walk_${String(walkFrame).padStart(2,'0')}`);
      }
    });
  }

  private playCookAnim() {
    this.stopAnims();
    let cookFrame = 0;
    this.cookTimer = this.time.addEvent({
      delay: 133, loop: true,
      callback: () => {
        cookFrame = (cookFrame + 1) % 30;
        this.chef.setTexture(`chef_cooking_${String(cookFrame).padStart(2,'0')}`);
      }
    });
  }

  private playDeliverAnim() {
    this.stopAnims();
    let dFrame = 0;
    this.deliverTimer = this.time.addEvent({
      delay: 100, loop: true,
      callback: () => {
        dFrame = (dFrame + 1) % 20;
        this.chef.setTexture(`chef_walk_with_pizza_${String(dFrame).padStart(2,'0')}`);
      }
    });
  }

  private startGame() {
    this.playerState = 'idle';
    this.foodItem.setVisible(false);
    this.cookBarBg.setVisible(false);
    this.cookBarFill.setVisible(false);
    if (this.cookTween) {
      this.cookTween.stop();
    }

    useGameStore.getState().resetGame();
    useGameStore.getState().setGameStatus('playing');
    this.generateOrder();
    this.playIdleAnim();
  }

  private generateOrder() {
    const store = useGameStore.getState();
    if (store.gameStatus !== 'playing') return;

    if (store.orders.length < 3) {
      const newOrder = {
        id: Math.random().toString(36).substring(7),
        patience: PATIENCE_TIME,
        maxPatience: PATIENCE_TIME,
        status: 'pending' as const
      };
      store.addOrder(newOrder);
    }
  }

  private handleFridgeClick() {
    if (this.playerState === 'idle') {
      this.playerState = 'holding_ingredient';
      this.foodItem.setVisible(true);
      this.foodItem.setAlpha(0.5); // indicates raw

      // Move to fridge
      this.tweens.add({
        targets: [this.chef, this.foodItem],
        x: 250,
        duration: 300,
        onComplete: () => this.playIdleAnim()
      });
    }
  }

  private handleStoveClick() {
    if (this.playerState === 'holding_ingredient') {
      this.playerState = 'cooking';

      // Move to stove
      this.tweens.add({
        targets: [this.chef, this.foodItem],
        x: 400,
        duration: 300,
        onComplete: () => {
          this.playCookAnim();
          this.foodItem.setVisible(false);
          this.cookBarBg.setVisible(true);
          this.cookBarFill.setVisible(true);
          this.cookBarFill.scaleX = 0;

          this.cookTween = this.tweens.add({
            targets: this.cookBarFill,
            scaleX: 1,
            duration: COOKING_TIME,
            onComplete: () => {
              this.playerState = 'holding_food';
              this.cookBarBg.setVisible(false);
              this.cookBarFill.setVisible(false);
              this.foodItem.setVisible(true);
              this.foodItem.setAlpha(1); // indicates cooked
              this.playDeliverAnim();
            }
          });
        }
      });
    }
  }

  private handleCustomerClick() {
    if (this.playerState === 'holding_food') {
      const store = useGameStore.getState();
      const currentOrder = store.orders[0];

      if (currentOrder) {
        // Move to customer
        this.tweens.add({
          targets: [this.chef, this.foodItem],
          x: 550,
          duration: 300,
          onComplete: () => {
            this.playerState = 'idle';
            this.foodItem.setVisible(false);
            store.completeOrder(currentOrder.id);
            this.playIdleAnim();

            // Move back to center
            this.tweens.add({
              targets: this.chef,
              x: 300,
              duration: 300
            });

            if (store.completedOrders + 1 >= ORDERS_TO_WIN) {
              store.setGameStatus('won');
              EventBus.emit('game-over', { result: 'won' });
            } else {
              this.generateOrder();
            }
          }
        });
      }
    }
  }

  update(time: number, delta: number) {
    const store = useGameStore.getState();
    if (store.gameStatus !== 'playing') return;

    // Throttle store sync
    if (time - this.lastTimeSync > 100) {
      this.lastTimeSync = time;

      // Update time remaining
      const timeRemaining = store.timeRemaining - 0.1; // roughly 100ms
      store.updateTime(timeRemaining);

      if (timeRemaining <= 0) {
        store.setGameStatus('lost');
        EventBus.emit('game-over', { result: 'lost' });
        return;
      }

      // Update patience
      store.orders.forEach(order => {
        const newPatience = order.patience - 100;
        if (newPatience <= 0) {
          store.failOrder(order.id);
          this.generateOrder();
        } else {
          store.updateOrderPatience(order.id, newPatience);
        }
      });
    }
  }

  shutdown() {
    EventBus.off('start-game', this.startGame, this);
    EventBus.off('restart-game', this.startGame, this);
    EventBus.off('generate-order', this.generateOrder, this);
  }
}

import { Boot } from './scenes/Boot';
