export const HUD: React.FC = () => {
  const score = useGameStore(state => state.score);
  const timeRemaining = useGameStore(state => Math.ceil(state.timeRemaining));
  const orders = useGameStore(state => state.orders);

  return (
    <div className="absolute top-0 left-0 w-full p-4 pointer-events-none z-10 flex justify-between items-start">
      {/* Time and Score */}
      <div className="flex flex-col gap-2">
        <div className="bg-[#4A3B32] border-4 border-[#4A3B32] rounded-[24px] px-6 py-2 shadow-[0_4px_0_0_rgba(0,0,0,0.5)]">
          <span className="text-[#FF8C42] text-2xl font-bold">时间: {formatTime(timeRemaining)}</span>
        </div>
        <div className="bg-[#4A3B32] border-4 border-[#4A3B32] rounded-[24px] px-6 py-2 shadow-[0_4px_0_0_rgba(0,0,0,0.5)]">
          <span className="text-[#FF8C42] text-2xl font-bold">分数: {score}</span>
        </div>
      </div>

      {/* Orders */}
      <div className="flex gap-4">
        {orders.map((order, idx) => (
          <div key={order.id} className="bg-[#FDF8E1] border-4 border-[#4A3B32] rounded-[24px] p-4 flex flex-col items-center shadow-[0_4px_0_0_rgba(0,0,0,0.5)]">
            <div className="text-[#4A3B32] font-bold text-lg mb-2">订单 #{idx + 1}</div>
            <div className="w-16 h-16 bg-contain bg-center bg-no-repeat mb-2" style={{ backgroundImage: `url('/assets/cooking-pizza/Png/Others/Pizza.png')` }} />

            {/* Patience bar */}
            <div className="w-24 h-4 bg-[#FF8C42] rounded-full overflow-hidden border-2 border-[#4A3B32]">
              <div 
                className="h-full bg-[#4CAF50] transition-all duration-100" 
                style={{ width: `${(order.patience / order.maxPatience) * 100}%` }}
              />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, '0')}`;
};

