import React, { useEffect, useRef } from 'react';
import StartGame from './game/main';
import { HUD } from './components/HUD';
import { StartScreen } from './components/StartScreen';
import { GameOverScreen } from './components/GameOverScreen';
import { useGameStore } from './game/model/store';
import { EventBus } from './game/EventBus';

function App() {
  const initialized = useRef(false);
  const gameStatus = useGameStore(state => state.gameStatus);

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    const game = StartGame('game-container');

    return () => {
      game.destroy(true);
      initialized.current = false;
    };
  }, []);

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-[#FDF8E1] font-sans">
      {/* Phaser Game Container */}
      <div id="game-container" className="absolute inset-0 w-full h-full z-0" />

      {/* UI Overlays */}
      {gameStatus === 'playing' && <HUD />}
      {gameStatus === 'idle' && <StartScreen />}
      {(gameStatus === 'won' || gameStatus === 'lost') && <GameOverScreen />}
    </div>
  );
}

export default App;

